'use strict';

/**
 * 生成 OpenCode hook plugin 文件内容字符串
 * Plugin 监听 session.created 事件，上报 { opencodeBaseUrl, sessionId, cwd } 到 Walker
 * 硬编码 loopback 地址，不包含任何敏感信息（token 等）
 */

/**
 * 生成 plugin 文件源码字符串
 * @param {number} walkerPort - Walker 监听端口
 * @returns {string} plugin JS 文件内容
 */
function getPluginSource(walkerPort) {
  const port = Number(walkerPort) || 8787;
  return [
    "// Walker auto-attach hook plugin",
    "// Auto-generated by Walker. Do not edit; Walker will not overwrite this file if it exists.",
    "",
    "var WALKER_URL = 'http://127.0.0.1:" + port + "/opencode/hook/session-created';",
    "var OPENCODE_BASE_URL = (typeof process !== 'undefined' && process.env && process.env.OPENCODE_SERVER_URL) || 'http://localhost:4096';",
    "",
    "function report(sessionId, cwd) {",
    "  try {",
    "    var payload = JSON.stringify({",
    "      opencodeBaseUrl: OPENCODE_BASE_URL,",
    "      sessionId: sessionId,",
    "      cwd: cwd || ''",
    "    });",
    "    var url = WALKER_URL;",
    "    if (typeof fetch === 'function') {",
    "      fetch(url, {",
    "        method: 'POST',",
    "        headers: { 'Content-Type': 'application/json' },",
    "        body: payload,",
    "      }).catch(function () { /* Walker unreachable: silent ignore */ });",
    "    } else if (typeof require === 'function') {",
    "      try {",
    "        var http = require('http');",
    "        var parsed = new (require('url').URL)(url);",
    "        var req = http.request({",
    "          hostname: parsed.hostname,",
    "          port: parsed.port,",
    "          path: parsed.pathname,",
    "          method: 'POST',",
    "          headers: { 'Content-Type': 'application/json' }",
    "        }, function () {});",
    "        req.on('error', function () { /* Walker unreachable: silent ignore */ });",
    "        req.write(payload);",
    "        req.end();",
    "      } catch (e) { /* silent ignore */ }",
    "    }",
    "  } catch (e) { /* silent ignore */ }",
    "}",
    "",
    "function extractCwd(eventData, ctx) {",
    "  if (eventData && eventData.session && eventData.session.cwd) return eventData.session.cwd;",
    "  if (eventData && eventData.cwd) return eventData.cwd;",
    "  if (ctx && ctx.directory) return ctx.directory;",
    "  if (typeof process !== 'undefined' && process.cwd) {",
    "    try { return process.cwd(); } catch (e) {}",
    "  }",
    "  return '';",
    "}",
    "",
    "function extractSessionId(eventData) {",
    "  if (!eventData) return '';",
    "  if (eventData.session && eventData.session.id) return eventData.session.id;",
    "  if (eventData.id) return eventData.id;",
    "  if (eventData.sessionId) return eventData.sessionId;",
    "  return '';",
    "}",
    "",
    "export const WalkerHookPlugin = async function (ctx) {",
    "  return {",
    "    event: async function (_a) {",
    "      var ev = _a && _a.event;",
    "      if (!ev || ev.type !== 'session.created') return;",
    "      var sessionId = extractSessionId(ev.properties || ev.data || ev);",
    "      if (!sessionId) return;",
    "      var cwd = extractCwd(ev.properties || ev.data || ev, ctx);",
    "      report(sessionId, cwd);",
    "    },",
    "  };",
    "};",
    "",
  ].join('\n');
}

module.exports = { getPluginSource };
